  { re: /\u9810\u5b9a\u5831\u5230\u65e5\u671f[\uff1a:]\s*(\d{4})\u5e74(\d{1,2})\u6708(\d{1,2})\u65e5/, fn: m => m[1]+'-'+m[2].padStart(2,'0')+'-'+m[3].padStart(2,'0') },
];
