  email_subject: base.email_subject,
  email_web_link: base.email_web_link,
  sender: base.sender,
  received_at: base.received_at,
  source_type: 'onboarding',
  name: base.name_from_subject || aiResult.name || '未知姓名',
  scheduled_onboard_date: guardOnboardYear(regexDate || aiResult.scheduled_onboard_date || null, base.received_at),
  raw_department: rawDepartment,
  raw_position: rawPosition,
  department: canonicalDepartment || rawDepartment,
  position: canonicalPosition || rawPosition,
